<template>
	<div
		ref="containerRef"
		:class="`grid place-items-center ${props.className}`"
		:style="{
  gridTemplateColumns: `repeat(${props.columns}, 1fr)`,
  gridTemplateRows: `repeat(${props.rows}, 1fr)`,
  width: props.containerSize,
  height: props.containerSize,
  ...props.style
}"
	>
		<span
			v-for="i in total"
			:key="i"
			class="block origin-center"
			:style="{
  'backgroundColor': props.lineColor,
  'width': props.lineWidth,
  'height': props.lineHeight,
  '--rotate': `${props.baseAngle}deg`,
  'transform': 'rotate(var(--rotate))',
  'willChange': 'transform'
}"
		/>
	</div>
</template>

<script setup>
import { computed, onMounted, onUnmounted, ref } from "vue";
const props = defineProps({
  rows: { type: Number, required: false, default: 9 },
  columns: { type: Number, required: false, default: 9 },
  containerSize: { type: String, required: false, default: "80vmin" },
  lineColor: { type: String, required: false, default: "#efefef" },
  lineWidth: { type: String, required: false, default: "1vmin" },
  lineHeight: { type: String, required: false, default: "6vmin" },
  baseAngle: { type: Number, required: false, default: -10 },
  className: { type: String, required: false, default: "" },
  style: { type: Object, required: false, default: () => ({}) }
});
const containerRef = ref(null);
const total = computed(() => props.rows * props.columns);
const onPointerMove = (pointer) => {
  const container = containerRef.value;
  if (!container) return;
  const items = container.querySelectorAll("span");
  items.forEach((item) => {
    const rect = item.getBoundingClientRect();
    const centerX = rect.x + rect.width / 2;
    const centerY = rect.y + rect.height / 2;
    const b = pointer.x - centerX;
    const a = pointer.y - centerY;
    const c = Math.sqrt(a * a + b * b) || 1;
    const r = Math.acos(b / c) * 180 / Math.PI * (pointer.y > centerY ? 1 : -1);
    item.style.setProperty("--rotate", `${r}deg`);
  });
};
const handlePointerMove = (e) => {
  onPointerMove({ x: e.x, y: e.y });
};
onMounted(() => {
  const container = containerRef.value;
  if (!container) return;
  window.addEventListener("pointermove", handlePointerMove);
  const items = container.querySelectorAll("span");
  if (items.length) {
    const middleIndex = Math.floor(items.length / 2);
    const rect = items[middleIndex].getBoundingClientRect();
    onPointerMove({ x: rect.x, y: rect.y });
  }
});
onUnmounted(() => {
  window.removeEventListener("pointermove", handlePointerMove);
});
</script>
